import subprocess
import os
import sys
from pathlib import Path

def convertDocument(input_file, output_file, format_type):
    """
    Convert documents between formats using LibreOffice headless mode.
    
    Args:
        input_file (str): Path to the input file
        output_file (str): Path to the output file
        format_type (str): Target format (e.g., 'pdf', 'docx', 'jpg')
    
    Returns:
        bool: True if conversion successful, False otherwise
    """
    # Validate input file exists
    if not os.path.exists(input_file):
        raise FileNotFoundError(f"Input file not found: {input_file}")
    
    # Validate LibreOffice is installed
    try:
        subprocess.run(['libreoffice', '--version'], 
                      check=True, capture_output=True, text=True)
    except (subprocess.CalledProcessError, FileNotFoundError):
        raise RuntimeError("LibreOffice not found. Please install LibreOffice.")
    
    # Sanitize paths to prevent path traversal attacks
    input_path = Path(input_file).resolve()
    output_path = Path(output_file).resolve()
    
    # Ensure paths are within allowed directories
    if not input_path.is_file() or not output_path.parent.is_dir():
        raise ValueError("Invalid file paths")
    
    # Validate format type (whitelist of allowed formats)
    allowed_formats = {
        'pdf', 'docx', 'doc', 'txt', 'html', 'odt', 'rtf', 'xls', 'xlsx',
        'ppt', 'pptx', 'jpg', 'jpeg', 'png', 'bmp', 'gif'
    }
    
    if format_type.lower() not in allowed_formats:
        raise ValueError(f"Unsupported format: {format_type}")
    
    # Build LibreOffice command
    try:
        cmd = [
            'libreoffice',
            '--headless',
            '--convert-to',
            format_type.lower(),
            '--outdir',
            str(output_path.parent),
            str(input_path)
        ]
        
        # Execute conversion
        result = subprocess.run(
            cmd,
            check=True,
            capture_output=True,
            text=True,
            timeout=300  # 5 minute timeout
        )
        
        # Verify output file was created
        if not output_path.exists():
            raise RuntimeError("Conversion failed: output file not created")
            
        return True
        
    except subprocess.TimeoutExpired:
        raise TimeoutError("LibreOffice conversion timed out")
    except subprocess.CalledProcessError as e:
        raise RuntimeError(f"LibreOffice conversion failed: {e.stderr}")
    except Exception as e:
        raise RuntimeError(f"Conversion error: {str(e)}")

